css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #fff9f7; color: #2b2330; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 22px 60px; border-bottom: 1px solid #f3e4e1; }
.brand { font-size: 20px; font-weight: 800; }
.nav-links { display: flex; gap: 28px; }
.nav-links a { color: #8a7c84; text-decoration: none; font-size: 14px; font-weight: 600; }
.nav-links a.active { color: #ec4899; }
.search { font-size: 16px; cursor: pointer; }
.hero { display: flex; gap: 40px; padding: 50px 60px; align-items: center; flex-wrap: wrap; }
.hero-img { width: 320px; height: 280px; background: linear-gradient(150deg, #fce7f3, #fbcfe8); border-radius: 24px; display: flex; align-items: center; justify-content: center; font-size: 80px; flex-shrink: 0; }
.cat { display: inline-block; background: rgba(236,72,153,0.1); color: #ec4899; font-size: 11.5px; font-weight: 700; padding: 4px 12px; border-radius: 999px; margin-bottom: 12px; }
.hero-text h1 { font-size: 36px; font-weight: 800; line-height: 1.3; margin-bottom: 14px; color: #2b2330; }
.hero-text p { color: #8a7c84; font-size: 15px; line-height: 1.7; margin-bottom: 18px; max-width: 480px; }
.meta { display: flex; align-items: center; gap: 10px; font-size: 13px; color: #a39199; font-weight: 600; }
.meta.small { margin-top: 12px; }
.avatar { width: 28px; height: 28px; border-radius: 50%; background: linear-gradient(135deg, #ec4899, #fbcfe8); display: flex; align-items: center; justify-content: center; color: white; font-size: 12px; font-weight: 700; }
.posts { padding: 30px 60px 60px; }
.posts h2 { font-size: 26px; font-weight: 800; margin-bottom: 24px; }
.post-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 24px; }
.post-card { background: white; border: 1px solid #f3e4e1; border-radius: 18px; padding: 18px; cursor: pointer; transition: 0.15s; }
.post-card:hover { transform: translateY(-4px); box-shadow: 0 16px 30px rgba(236,72,153,0.1); }
.post-img { height: 130px; background: #fdf2f8; border-radius: 14px; display: flex; align-items: center; justify-content: center; font-size: 44px; margin-bottom: 14px; }
.post-card h3 { font-size: 16px; font-weight: 700; margin: 10px 0 8px; }
.post-card p { color: #a39199; font-size: 13px; line-height: 1.6; }
.categories-strip { display: flex; gap: 10px; padding: 0 60px 50px; flex-wrap: wrap; }
.chip { background: #fdf2f8; color: #ec4899; padding: 8px 18px; border-radius: 999px; font-size: 13px; font-weight: 700; }
.newsletter { background: linear-gradient(135deg, #fce7f3, #fdf2f8); text-align: center; padding: 60px; }
.newsletter h2 { font-size: 28px; font-weight: 800; margin-bottom: 10px; }
.newsletter p { color: #a39199; font-size: 14px; margin-bottom: 24px; }
.form-row { display: flex; gap: 10px; max-width: 400px; margin: 0 auto; }
.form-row input { flex: 1; padding: 14px 18px; border-radius: 999px; border: 1px solid #f3c9dc; background: white; font-size: 14px; outline: none; }
.form-row button { background: #ec4899; border: none; color: white; padding: 14px 26px; border-radius: 999px; font-size: 14px; font-weight: 700; cursor: pointer; }
@media (max-width: 900px) { .hero { padding: 30px 24px; } .posts, .newsletter, .categories-strip { padding: 30px 24px; } .hero-text h1 { font-size: 28px; } }

js:
document.querySelectorAll('.post-card').forEach(card => {
  card.addEventListener('click', () => {
    const title = card.querySelector('h3').textContent;
    alert(`"${title}" yazısı açılıyor...`);
  });
});

function subscribe() {
  const input = document.querySelector('.form-row input');
  if (input.value.includes('@')) {
    alert('Bültene başarıyla katıldın!');
    input.value = '';
  } else {
    alert('Geçerli bir e-posta girin.');
  }
}
